-- 236_euer_views_tenant_name_fix.sql
-- Bringt v_euer_einnahmen / v_euer_ausgaben auf den 2026-07-13 server-seitig angewandten Stand:
-- organisation_name = Dojo 2 'TDA International', Dojo 3 'Kampfkunstschule Schreiner',
-- sonst echter Dojoname (statt hart 'Kampfkunstschule Schreiner' fuer ALLE ausser Dojo 2).
-- Ersetzt die alte, leakende CASE-Logik aus Migration 098. Idempotent via CREATE OR REPLACE.
-- Definition ist ein byte-exaktes Abbild der Live-Views (bereits gefixt).

CREATE OR REPLACE VIEW `v_euer_einnahmen` AS select 'Beleg' AS `quelle`,`b`.`beleg_id` AS `referenz_id`,`b`.`dojo_id` AS `dojo_id`,`b`.`organisation_name` AS `organisation_name`,`b`.`beleg_datum` AS `datum`,`b`.`betrag_brutto` AS `betrag_brutto`,`b`.`kategorie` AS `kategorie`,`b`.`beschreibung` AS `beschreibung`,year(`b`.`beleg_datum`) AS `jahr`,month(`b`.`beleg_datum`) AS `monat` from `buchhaltung_belege` `b` where `b`.`buchungsart` = 'einnahme' and `b`.`storniert` = 0 and `b`.`kategorie` not in ('privateinlage','privatentnahme') and `b`.`privat` = 0 union all select 'Beitrag' AS `quelle`,`b`.`beitrag_id` AS `referenz_id`,coalesce(`b`.`dojo_id`,1) AS `dojo_id`,case when `b`.`dojo_id` = 2 then 'TDA International' when `b`.`dojo_id` = 3 then 'Kampfkunstschule Schreiner' else coalesce((select `dojo`.`dojoname` from `dojo` where `dojo`.`id` = `b`.`dojo_id`),'Dojo') end AS `organisation_name`,`b`.`zahlungsdatum` AS `datum`,`b`.`betrag` AS `betrag_brutto`,'betriebseinnahmen' AS `kategorie`,concat('Mitgliedsbeitrag ',month(`b`.`zahlungsdatum`),'/',year(`b`.`zahlungsdatum`)) AS `beschreibung`,year(`b`.`zahlungsdatum`) AS `jahr`,month(`b`.`zahlungsdatum`) AS `monat` from `beitraege` `b` where `b`.`bezahlt` = 1 and `b`.`rechnung_id` is null and `b`.`euer_ausblenden` = 0 union all select 'Rechnung' AS `quelle`,`r`.`rechnung_id` AS `referenz_id`,coalesce(`r`.`dojo_id`,1) AS `dojo_id`,case when `r`.`dojo_id` = 2 then 'TDA International' when `r`.`dojo_id` = 3 then 'Kampfkunstschule Schreiner' else coalesce((select `dojo`.`dojoname` from `dojo` where `dojo`.`id` = `r`.`dojo_id`),'Dojo') end AS `organisation_name`,`r`.`bezahlt_am` AS `datum`,coalesce(`r`.`brutto_betrag`,`r`.`betrag`) AS `betrag_brutto`,'betriebseinnahmen' AS `kategorie`,concat('Rechnung ',`r`.`rechnungsnummer`) AS `beschreibung`,year(`r`.`bezahlt_am`) AS `jahr`,month(`r`.`bezahlt_am`) AS `monat` from `rechnungen` `r` where `r`.`status` = 'bezahlt' and `r`.`bezahlt_am` is not null union all select 'Verkauf' AS `quelle`,`v`.`verkauf_id` AS `referenz_id`,coalesce(`v`.`dojo_id`,1) AS `dojo_id`,case when `v`.`dojo_id` = 2 then 'TDA International' when `v`.`dojo_id` = 3 then 'Kampfkunstschule Schreiner' else coalesce((select `dojo`.`dojoname` from `dojo` where `dojo`.`id` = `v`.`dojo_id`),'Dojo') end AS `organisation_name`,`v`.`verkauf_datum` AS `datum`,`v`.`brutto_gesamt_cent` / 100 AS `betrag_brutto`,'betriebseinnahmen' AS `kategorie`,concat('Verkauf ',`v`.`bon_nummer`) AS `beschreibung`,year(`v`.`verkauf_datum`) AS `jahr`,month(`v`.`verkauf_datum`) AS `monat` from `verkaeufe` `v` union all select 'Bank' AS `quelle`,`bt`.`transaktion_id` AS `referenz_id`,`bt`.`dojo_id` AS `dojo_id`,`bt`.`organisation_name` AS `organisation_name`,`bt`.`buchungsdatum` AS `datum`,`bt`.`betrag` AS `betrag_brutto`,coalesce(`bt`.`kategorie`,'betriebseinnahmen') AS `kategorie`,concat(`bt`.`auftraggeber_empfaenger`,': ',coalesce(`bt`.`verwendungszweck`,'')) AS `beschreibung`,year(`bt`.`buchungsdatum`) AS `jahr`,month(`bt`.`buchungsdatum`) AS `monat` from `bank_transaktionen` `bt` where `bt`.`betrag` > 0 and `bt`.`status` = 'zugeordnet' and `bt`.`kategorie` not in ('privateinlage','privatentnahme') and `bt`.`beleg_id` is null and (`bt`.`match_typ` is null or `bt`.`match_typ` not in ('rechnung','beitrag','verkauf')) union all select 'Kasse' AS `quelle`,`k`.`eintrag_id` AS `referenz_id`,coalesce(`k`.`dojo_id`,1) AS `dojo_id`,case when `k`.`dojo_id` = 2 then 'TDA International' when `k`.`dojo_id` = 3 then 'Kampfkunstschule Schreiner' else coalesce((select `dojo`.`dojoname` from `dojo` where `dojo`.`id` = `k`.`dojo_id`),'Dojo') end AS `organisation_name`,`k`.`geschaeft_datum` AS `datum`,`k`.`betrag_cent` / 100 AS `betrag_brutto`,'betriebseinnahmen' AS `kategorie`,`k`.`beschreibung` AS `beschreibung`,year(`k`.`geschaeft_datum`) AS `jahr`,month(`k`.`geschaeft_datum`) AS `monat` from `kassenbuch` `k` where `k`.`bewegungsart` = 'einnahme';

CREATE OR REPLACE VIEW `v_euer_ausgaben` AS select 'Beleg' AS `quelle`,`b`.`beleg_id` AS `referenz_id`,`b`.`dojo_id` AS `dojo_id`,`b`.`organisation_name` AS `organisation_name`,`b`.`beleg_datum` AS `datum`,round(`b`.`betrag_brutto` * (1 - coalesce(`b`.`privatanteil_prozent`,0) / 100),2) AS `betrag_brutto`,`b`.`kategorie` AS `kategorie`,`b`.`beschreibung` AS `beschreibung`,year(`b`.`beleg_datum`) AS `jahr`,month(`b`.`beleg_datum`) AS `monat` from `buchhaltung_belege` `b` where `b`.`buchungsart` = 'ausgabe' and `b`.`storniert` = 0 and `b`.`kategorie` not in ('privateinlage','privatentnahme','anlagevermÃƒÂ¶gen','betriebseinnahmen') and `b`.`privat` = 0 union all select 'AfA' AS `quelle`,`ap`.`afa_id` AS `referenz_id`,`ap`.`dojo_id` AS `dojo_id`,`ap`.`organisation_name` AS `organisation_name`,makedate(`ap`.`afa_jahr`,1) AS `datum`,`ap`.`afa_betrag` AS `betrag_brutto`,'abschreibungen' AS `kategorie`,concat('AfA: ',`ar`.`bezeichnung`,' (',`ap`.`afa_jahr`,')') AS `beschreibung`,`ap`.`afa_jahr` AS `jahr`,1 AS `monat` from (`afa_positionen` `ap` join `anlage_register` `ar` on(`ar`.`anlage_id` = `ap`.`anlage_id`)) where `ap`.`afa_jahr` <= year(curdate()) and `ar`.`aktiv` = 1 union all select 'Bank' AS `quelle`,`bt`.`transaktion_id` AS `referenz_id`,`bt`.`dojo_id` AS `dojo_id`,`bt`.`organisation_name` AS `organisation_name`,`bt`.`buchungsdatum` AS `datum`,abs(`bt`.`betrag`) AS `betrag_brutto`,coalesce(`bt`.`kategorie`,'sonstige_kosten') AS `kategorie`,concat(`bt`.`auftraggeber_empfaenger`,': ',coalesce(`bt`.`verwendungszweck`,'')) AS `beschreibung`,year(`bt`.`buchungsdatum`) AS `jahr`,month(`bt`.`buchungsdatum`) AS `monat` from `bank_transaktionen` `bt` where `bt`.`betrag` < 0 and `bt`.`status` = 'zugeordnet' and `bt`.`kategorie` not in ('privateinlage','privatentnahme','betriebseinnahmen') and `bt`.`beleg_id` is null and (`bt`.`match_typ` is null or `bt`.`match_typ` not in ('rechnung','beitrag','verkauf')) union all select 'Kasse' AS `quelle`,`k`.`eintrag_id` AS `referenz_id`,coalesce(`k`.`dojo_id`,1) AS `dojo_id`,case when `k`.`dojo_id` = 2 then 'TDA International' when `k`.`dojo_id` = 3 then 'Kampfkunstschule Schreiner' else coalesce((select `dojo`.`dojoname` from `dojo` where `dojo`.`id` = `k`.`dojo_id`),'Dojo') end AS `organisation_name`,`k`.`geschaeft_datum` AS `datum`,`k`.`betrag_cent` / 100 AS `betrag_brutto`,'sonstige_kosten' AS `kategorie`,`k`.`beschreibung` AS `beschreibung`,year(`k`.`geschaeft_datum`) AS `jahr`,month(`k`.`geschaeft_datum`) AS `monat` from `kassenbuch` `k` where `k`.`bewegungsart` = 'ausgabe';
